select ent_code, out_put_id, template_code, max(record_date) as record_date
from t_ops_record

    review_status = 4


            and ent_code = #{entCode}


            and ent_code in

                #{entCode}




        and out_put_id = #{outPutId}


        and template_code = #{templateCode}


        and ops_user_id = #{operator}


group by ent_code, out_put_id, template_code

select
    r.record_id, r.ent_code, r.out_put_id, r.template_code, r.ops_unit_id, r.record_date, r.ops_user_id,
    r.qualified_flag, r.review_status, r.create_by, r.create_time, r.update_by, r.update_time,
    ext.unit_name as ops_unit_name, e.ent_name, e.region, o.out_put_code, o.out_put_name, u.user_name as ops_user_name, u.nick_name as ops_nick_name
from t_ops_record r
left join t_bas_enterprise e on e.ent_code = r.ent_code
left join t_ent_out_put_info o on o.out_put_id = r.out_put_id
left join sys_user u on u.user_id = r.ops_user_id
left join t_ext_unit_lib ext on ext.unit_code = r.ops_unit_id



            and r.ent_code = #{entCode}


            and r.ent_code in

                #{entCode}




        and (e.region = #{region} or e.region like CONCAT(#{region}, ',%'))


        and r.out_put_id = #{outPutId}


        and r.template_code = #{templateCode}


        and r.ops_user_id = #{opsUserId}


        and r.record_date between #{recordStart} and #{recordEnd}


order by r.record_id desc

mapper.update:
update t_ops_record

    review_status = #{reviewStatus}


            , qualified_flag = #{qualifiedFlag}, record_array = #{recordArray}

                , record_date = #{recordDate}

            , update_by = #{updateBy}, update_time = now()


            , qualified_flag = #{qualifiedFlag}, record_array = #{recordArray}, record_date = #{recordDate}
            , update_by = #{updateBy}, update_time = now()



where record_id = #{recordId}

mapper.select:
select
    template_code as templateCode,
    sum(auto_tasks) as autoTasks,
    sum(manual_tasks) as manualTasks,
    sum(completed_tasks) as completedTasks,
    sum(qualified_tasks) as qualifiedTasks,
    sum(unqualified_tasks) as unqualifiedTasks
from t_ops_task_stat



            and ent_code = #{entCode}


            and ent_code in

                #{entCode}




        and out_put_id = #{outPutId}


        and template_code = #{templateCode}


        and operator = #{opsUserId}


        and task_stat_date between DATE(#{recordStart}) and DATE(#{recordEnd})


group by template_code
